import { motion } from 'framer-motion';

const Login = () => {
  return (
    <div className="flex items-center justify-center min-h-screen bg-black">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-[#121212] p-10 rounded-xl w-full max-w-md shadow-2xl border border-gray-800"
      >
        <h2 className="text-3xl font-bold text-center mb-8">Iniciar Sesión</h2>
        
        <form className="flex flex-col gap-4">
          <input 
            type="email" 
            placeholder="Correo electrónico" 
            className="p-3 bg-[#2a2a2a] border border-transparent focus:border-[#1DB954] outline-none rounded-md"
          />
          <input 
            type="password" 
            placeholder="Contraseña" 
            className="p-3 bg-[#2a2a2a] border border-transparent focus:border-[#1DB954] outline-none rounded-md"
          />
          
          <motion.button 
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className="bg-[#1DB954] text-black font-bold p-3 rounded-full mt-4 hover:bg-[#1ed760] transition"
          >
            ENTRAR
          </motion.button>
        </form>

        <p className="text-center text-sm text-gray-400 mt-6">
          ¿No tienes cuenta? <span className="text-white font-bold cursor-pointer hover:underline">Regístrate</span>
        </p>
      </motion.div>
    </div>
  );
};
